5	const router = Router();
6	
7	// GET /posts/:postId/comments - list all comments for a post
8	router.get("/posts/:postId/comments", (req, res) => {
9	  const postId = parseInt(req.params.postId, 10);
10	  const post = posts.find((p) => p.id === postId);
11	  if (!post) {
12	    res.status(404).json({ error: "Post not found" });
13	    return;
14	  }
15	  const postComments = comments.filter((c) => c.postId === postId);
16	  res.json(postComments);
17	});
18	
19	// GET /comments/:id - get a single comment
20	router.get("/comments/:id", (req, res) => {
21	  const id = parseInt(req.params.id, 10);
22	  const comment = comments.find((c) => c.id === id);
23	  if (!comment) {
24	    res.status(404).json({ error: "Comment not found" });
25	    return;
26	  }
27	  res.json(comment);
28	});
29	
30	// POST /posts/:postId/comments - create a comment on a post
31	router.post("/posts/:postId/comments", (req, res) => {
32	  const postId = parseInt(req.params.postId, 10);
33	  const post = posts.find((p) => p.id === postId);
34	  if (!post) {
35	    res.status(404).json({ error: "Post not found" });
36	    return;
37	  }
38	  const { body, userId } = req.body;
39	  if (!body) {
40	    res.status(400).json({ error: "body is required" });
41	    return;
42	  }
43	  const newComment: Comment = {
44	    id: nextId(comments),
45	    postId,
46	    userId: userId || 1,
47	    body,
48	    createdAt: new Date().toISOString(),
49	  };
50	  comments.push(newComment);
51	  res.status(201).json(newComment);
52	});
53	
54	// PUT /comments/:id - update a comment
55	router.put("/comments/:id", (req, res) => {
56	  const id = parseInt(req.params.id, 10);
57	  const index = comments.findIndex((c) => c.id === id);
58	  if (index === -1) {
59	    res.status(404).json({ error: "Comment not found" });
60	    return;
61	  }
62	  const { body } = req.body;
63	  if (body) comments[index].body = body;
64	  res.json(comments[index]);
65	});
66	
67	// DELETE /comments/:id - delete a comment
68	router.delete("/comments/:id", (req, res) => {
69	  const id = parseInt(req.params.id, 10);
70	  const index = comments.findIndex((c) => c.id === id);
71	  if (index === -1) {
72	    res.status(404).json({ error: "Comment not found" });
73	    return;
74	  }
75	  const deleted = comments.splice(index, 1);
76	  res.json(deleted[0]);
77	});
78	
79	export { router as commentsRouter };
