### 6. Route Implementation Patterns

#### `/src/routes/posts.ts`
**HTTP Methods Supported:**
- `GET /` - List all posts
- `GET /:id` - Get single post
- `POST /` - Create new post
- `PUT /:id` - Update post
- `DELETE /:id` - Delete post

**Current Pattern:**
- ID parsing from URL params (`parseInt(req.params.id, 10)`)
- Direct array mutations (`posts.push()`, `posts.splice()`)
- Manual ID finding with `.find()` and `.findIndex()`
- Basic validation (required fields)
- Error responses with 404/400 status codes
- **No authentication checks** (routes are open)
- **No ownership validation** (any user can update/delete any post)

**Full Code:**
```typescript
import { Router } from "express";
import { posts, nextId } from "../db.js";
import { Post } from "../types.js";

const router = Router();

// GET /posts - list all posts
router.get("/", (req, res) => {
  res.json(posts);
});

// GET /posts/:id - get a single post
router.get("/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const post = posts.find((p) => p.id === id);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  res.json(post);
});

// POST /posts - create a new post
router.post("/", (req, res) => {
  const { title, content, userId } = req.body;
  if (!title || !content) {
    res.status(400).json({ error: "title and content are required" });
    return;
  }
  const newPost: Post = {
    id: nextId(posts),
    title,
    content,
    userId: userId || 1,
    createdAt: new Date().toISOString(),
  };
  posts.push(newPost);
  res.status(201).json(newPost);
});

// PUT /posts/:id - update a post
router.put("/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  const { title, content } = req.body;
  if (title) posts[index].title = title;
  if (content) posts[index].content = content;
  res.json(posts[index]);
});

// DELETE /posts/:id - delete a post
router.delete("/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  const deleted = posts.splice(index, 1);
  res.json(deleted[0]);
});

export { router as postsRouter };
```

#### `/src/routes/comments.ts`
**HTTP Methods Supported:**
- `GET /posts/:postId/comments` - List comments for a post
- `GET /comments/:id` - Get single comment
- `POST /posts/:postId/comments` - Create comment on post
- `PUT /comments/:id` - Update comment
- `DELETE /comments/:id` - Delete comment

**Pattern:** Very similar to posts route
- Nested resource pattern for post comments
- Parent validation (post must exist before creating comment)
- **No authentication checks**
- **No ownership validation**

**Full Code:**
```typescript
import { Router } from "express";
import { comments, posts, nextId } from "../db.js";
import { Comment } from "../types.js";

const router = Router();

// GET /posts/:postId/comments - list all comments for a post
router.get("/posts/:postId/comments", (req, res) => {
  const postId = parseInt(req.params.postId, 10);
  const post = posts.find((p) => p.id === postId);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  const postComments = comments.filter((c) => c.postId === postId);
  res.json(postComments);
});

// GET /comments/:id - get a single comment
router.get("/comments/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const comment = comments.find((c) => c.id === id);
  if (!comment) {
    res.status(404).json({ error: "Comment not found" });
    return;
  }
  res.json(comment);
});

// POST /posts/:postId/comments - create a comment on a post
router.post("/posts/:postId/comments", (req, res) => {
  const postId = parseInt(req.params.postId, 10);
  const post = posts.find((p) => p.id === postId);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  const { body, userId } = req.body;
  if (!body) {
    res.status(400).json({ error: "body is required" });
    return;
  }
  const newComment: Comment = {
    id: nextId(comments),
    postId,
    userId: userId || 1,
    body,
    createdAt: new Date().toISOString(),
  };
  comments.push(newComment);
  res.status(201).json(newComment);
});

// PUT /comments/:id - update a comment
router.put("/comments/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = comments.findIndex((c) => c.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Comment not found" });
    return;
  }
  const { body } = req.body;
  if (body) comments[index].body = body;
  res.json(comments[index]);
});

// DELETE /comments/:id - delete a comment
router.delete("/comments/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = comments.findIndex((c) => c.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Comment not found" });
    return;
  }
  const deleted = comments.splice(index, 1);
  res.json(deleted[0]);
});

export { router as commentsRouter };
```

