  const postId = parseInt(req.params.postId, 10);
  const post = posts.find((p) => p.id === postId);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  const postComments = comments.filter((c) => c.postId === postId);
